CREATE TABLE IF NOT EXISTS products (id SERIAL PRIMARY KEY, category_id INT, name VARCHAR(255) NOT NULL, slug VARCHAR(255) NOT NULL UNIQUE, short_description TEXT, description TEXT, specs JSONB DEFAULT '{}', fps_data JSONB DEFAULT '{}', price NUMERIC(12,2) NOT NULL DEFAULT 0, old_price NUMERIC(12,2), image_url TEXT, gallery JSONB DEFAULT '[]', status VARCHAR(50) DEFAULT 'in_stock', is_featured BOOLEAN DEFAULT false, is_active BOOLEAN DEFAULT true, sort_order INT DEFAULT 0, created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW()); ALTER TABLE products ADD CONSTRAINT fk_products_category FOREIGN KEY (category_id) REFERENCES categories(id);